class Solution {
public:
    string shortestPalindrome(string s) {
        string rev_s = s;
        reverse(rev_s.begin(), rev_s.end());
        for (int i = 0; i <= s.size(); i++) {
            if (s.substr(0, s.size() - i) == rev_s.substr(i, s.size() - i)) {
                return rev_s.substr(0, i) + s;
            }
        }
        return "";
    }
};
```
